"use client";

import React, { useState, useEffect } from "react";
import axios from "axios";
import VoiceInput from "@/components/VoiceInput";
import ScreenPreview from "@/components/ScreenPreview";
import ActionLog from "@/components/ActionLog";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { Cpu, ShieldCheck, Zap, Activity, Globe, Send } from "lucide-react";
import { motion } from "framer-motion";

const API_BASE_URL = "http://localhost:8000";

export default function Home() {
  const [taskId, setTaskId] = useState<string | null>(null);
  const [taskStatus, setTaskStatus] = useState<any>({
    status: "idle",
    logs: [],
    last_screenshot: null
  });
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    let interval: any;
    if (taskId && (taskStatus.status === "running" || taskStatus.status === "starting")) {
      interval = setInterval(async () => {
        try {
          const response = await axios.get(`${API_BASE_URL}/task/${taskId}`);
          setTaskStatus(response.data);
          
          if (response.data.status === "completed" || response.data.status === "failed") {
            setIsProcessing(false);
            clearInterval(interval);
          }
        } catch (error) {
          console.error("Error polling task:", error);
        }
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [taskId, taskStatus.status]);

  const handleSendCommand = async (command: string) => {
    setIsProcessing(true);
    setTaskStatus({ status: "starting", logs: ["Initilizing agent environment...", "Analyzing initial intent..."], last_screenshot: null });
    
    try {
      const formData = new FormData();
      formData.append("command", command);
      
      const response = await axios.post(`${API_BASE_URL}/execute-task`, formData);
      setTaskId(response.data.task_id);
    } catch (error) {
      console.error("Error starting task:", error);
      setTaskStatus({ 
        status: "failed", 
        logs: ["Failed to connect to backend engine. Ensure the server is running on port 8000."], 
        last_screenshot: null 
      });
      setIsProcessing(false);
    }
  };

  return (
    <DashboardLayout status={taskStatus.status}>
      <div className="flex flex-col gap-10">
        {/* Welcome Section */}
        <div className="flex flex-col gap-2">
          <motion.h1 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white via-slate-200 to-slate-400"
          >
            Agent Console
          </motion.h1>
          <motion.p 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.1 }}
            className="text-slate-500 font-medium"
          >
            Manage and monitor your AI-driven web automation tasks.
          </motion.p>
        </div>

        {/* Stats Row */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {[
            { label: "Active Sessions", value: taskStatus.status === "running" ? "1" : "0", icon: Activity, color: "text-blue-400" },
            { label: "Target Domain", value: "Multi-Website", icon: Globe, color: "text-indigo-400" },
            { label: "AI Engine", value: "Gemini 2.0", icon: Cpu, color: "text-violet-400" },
            { label: "Automation Status", value: taskStatus.status === "completed" ? "Verified" : "Standby", icon: ShieldCheck, color: "text-emerald-400" },
          ].map((stat, i) => (
            <motion.div
              key={i}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.2 + i * 0.05 }}
              className="glass-card p-6 rounded-2xl flex items-center gap-4 group hover:border-white/10 transition-colors"
            >
              <div className={`p-3 bg-slate-800/50 rounded-xl group-hover:scale-110 transition-transform ${stat.color}`}>
                <stat.icon size={20} />
              </div>
              <div className="flex flex-col">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">{stat.label}</span>
                <span className="text-lg font-bold text-slate-100">{stat.value}</span>
              </div>
            </motion.div>
          ))}
        </div>

        {/* Main Workspace Layout */}
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 items-start">
          {/* Left: Input & Preview */}
          <div className="xl:col-span-8 flex flex-col gap-8">
            <VoiceInput 
              onSendCommand={handleSendCommand} 
              isProcessing={isProcessing} 
            />
            <ScreenPreview 
              screenshot={taskStatus.last_screenshot} 
              status={taskStatus.status} 
            />
          </div>

          {/* Right: Activity Logs */}
          <div className="xl:col-span-4 h-full">
            <div className="glass-card rounded-3xl p-8 sticky top-6">
              <ActionLog 
                logs={taskStatus.logs} 
                status={taskStatus.status} 
              />
            </div>
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
}
